using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    Department? GetDepartment(string code);
    List<Course> GetCourses(string? searchTerm = null, string? departmentCode = null);
    Course? GetCourse(int id);
    List<Course> GetFeaturedCourses();
    List<Course> GetCoursesByDepartment(string departmentCode);
    void SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = InitializeDepartments();
        _courses = InitializeCourses();
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string code) =>
        _departments.FirstOrDefault(d => d.Code.Equals(code, StringComparison.OrdinalIgnoreCase));

    public List<Course> GetCourses(string? searchTerm = null, string? departmentCode = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentCode))
        {
            query = query.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase));
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(string departmentCode) =>
        _courses.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase))
                .OrderBy(c => c.Code)
                .ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application this would persist to a database.
        // For this demo we simply validate the course exists.
        var course = GetCourse(request.CourseId);
        if (course is null)
        {
            throw new InvalidOperationException("The selected course does not exist.");
        }
    }

    private static List<Department> InitializeDepartments() =>
    [
        new() { Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
        new() { Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Code = "ENG", Name = "English", Description = "Literature, creative writing, and communication studies." },
        new() { Code = "HIST", Name = "History", Description = "World history, cultural studies, and historiography." },
        new() { Code = "BIO", Name = "Biology", Description = "Life sciences, ecology, genetics, and biotechnology." },
    ];

    private static List<Course> InitializeCourses() =>
    [
        new()
        {
            Id = 1, Code = "CS 101", Title = "Introduction to Computer Science",
            Description = "A broad introduction to computer science covering computational thinking, basic programming in Python, data representation, and an overview of how computers work. No prior experience required.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Room = "Tech Hall 201",
            DepartmentCode = "CS", IsFeatured = true,
            Instructor = new() { Name = "Dr. Ada Lovelace", Title = "Professor", Email = "alovelace@university.edu", Bio = "Dr. Lovelace has over 15 years of experience teaching introductory CS. Her research focuses on CS education and making computing accessible to all students.", OfficeHours = "Mon/Wed 2:00–4:00 PM", Office = "Tech Hall 305" }
        },
        new()
        {
            Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms",
            Description = "Study of fundamental data structures (arrays, linked lists, trees, hash tables, graphs) and algorithms (sorting, searching, graph traversal). Includes algorithm analysis using Big-O notation.",
            Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Room = "Tech Hall 105",
            DepartmentCode = "CS", IsFeatured = true,
            Instructor = new() { Name = "Dr. Alan Turing", Title = "Associate Professor", Email = "aturing@university.edu", Bio = "Dr. Turing specializes in algorithm design and computational complexity. He has published extensively on efficient graph algorithms.", OfficeHours = "Tue/Thu 1:00–3:00 PM", Office = "Tech Hall 310" }
        },
        new()
        {
            Id = 3, Code = "CS 310", Title = "Database Systems",
            Description = "Relational database design, SQL, normalization, transaction management, and an introduction to NoSQL databases. Students complete a semester-long project building a full database application.",
            Credits = 3, Schedule = "Mon/Wed 1:00–2:20 PM", Room = "Tech Hall 108",
            DepartmentCode = "CS", IsFeatured = false,
            Instructor = new() { Name = "Dr. Edgar Codd", Title = "Professor", Email = "ecodd@university.edu", Bio = "Dr. Codd is a pioneer in relational database theory with 20 years of industry and academic experience.", OfficeHours = "Mon 3:00–5:00 PM", Office = "Tech Hall 312" }
        },
        new()
        {
            Id = 4, Code = "MATH 101", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems. Emphasizes both conceptual understanding and computational skill.",
            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Room = "Science Bldg 202",
            DepartmentCode = "MATH", IsFeatured = true,
            Instructor = new() { Name = "Dr. Emmy Noether", Title = "Professor", Email = "enoether@university.edu", Bio = "Dr. Noether is an award-winning educator known for her ability to make abstract math intuitive. Her research spans abstract algebra and theoretical physics.", OfficeHours = "Wed/Fri 1:00–3:00 PM", Office = "Science Bldg 401" }
        },
