            Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Room = "Tech Hall 105",
            DepartmentCode = "CS", IsFeatured = true,
            Instructor = new() { Name = "Dr. Alan Turing", Title = "Associate Professor", Email = "aturing@university.edu", Bio = "Dr. Turing specializes in algorithm design and computational complexity. He has published extensively on efficient graph algorithms.", OfficeHours = "Tue/Thu 1:00–3:00 PM", Office = "Tech Hall 310" }
        },
        new()
        {
            Id = 3, Code = "CS 310", Title = "Database Systems",
            Description = "Relational database design, SQL, normalization, transaction management, and an introduction to NoSQL databases. Students complete a semester-long project building a full database application.",
            Credits = 3, Schedule = "Mon/Wed 1:00–2:20 PM", Room = "Tech Hall 108",
            DepartmentCode = "CS", IsFeatured = false,
