            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Room = "Science Bldg 202",
            DepartmentCode = "MATH", IsFeatured = true,
            Instructor = new() { Name = "Dr. Emmy Noether", Title = "Professor", Email = "enoether@university.edu", Bio = "Dr. Noether is an award-winning educator known for her ability to make abstract math intuitive. Her research spans abstract algebra and theoretical physics.", OfficeHours = "Wed/Fri 1:00–3:00 PM", Office = "Science Bldg 401" }
