+    public CatalogService()
+    {
+        _departments = InitializeDepartments();
+        _courses = InitializeCourses();
+    }
+
+    public List<Department> GetDepartments() => _departments;
+
+    public Department? GetDepartment(string code) =>
+        _departments.FirstOrDefault(d => d.Code.Equals(code, StringComparison.OrdinalIgnoreCase));
+
+    public List<Course> GetCourses(string? searchTerm = null, string? departmentCode = null)
+    {
+        var query = _courses.AsEnumerable();
+
+        if (!string.IsNullOrWhiteSpace(departmentCode))
+        {
+            query = query.Where(c => c.DepartmentCode.Equals(departmentCode, StringComparison.OrdinalIgnoreCase));
+        }
+
+        if (!string.IsNullOrWhiteSpace(searchTerm))
+        {
+            var term = searchTerm.Trim();
+            query = query.Where(c =>
+                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
+                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
+                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
+                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
+        }
+
+        return query.OrderBy(c => c.Code).ToList();
+    }
+
+    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
+
+    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
+
+    public List<Course> GetCoursesByDepartment(string departmentCode) =>
