@using UniversityCourseCatalog.Models

<div class="card h-100 shadow-sm">
    <div class="card-body d-flex flex-column">
        <span class="badge bg-primary mb-2 align-self-start">@Course.Code</span>
        <h5 class="card-title">@Course.Title</h5>
        <p class="card-text text-muted flex-grow-1">@Truncate(Course.Description, 120)</p>
        <div class="d-flex justify-content-between align-items-center mt-2">
            <small class="text-body-secondary">@Course.Credits credits &bull; @Course.Instructor.Name</small>
            <a href="@($"course/{Course.Id}")" class="btn btn-outline-primary btn-sm">View Details</a>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public required Course Course { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "…");
}

@using UniversityCourseCatalog.Models

<div class="row g-3 mb-4">
    <div class="col-md-8">
        <input type="text"
               class="form-control"
               placeholder="Search courses by title, code, or instructor…"
               @bind="SearchTerm"
               @bind:event="oninput"
               @bind:after="OnSearchChanged" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartment" @bind:after="OnSearchChanged">
            <option value="">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Code">@dept.Name</option>
            }
        </select>
    </div>
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public string SelectedDepartment { get; set; } = string.Empty;
    [Parameter] public EventCallback<(string Search, string Department)> OnFilterChanged { get; set; }
    [Parameter, EditorRequired] public required List<Department> Departments { get; set; }

    private async Task OnSearchChanged()
    {
        await OnFilterChanged.InvokeAsync((SearchTerm, SelectedDepartment));
    }
}

@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Components.Shared

@if (Courses.Count == 0)
{
    <div class="alert alert-info">
        No courses found matching your criteria. Try adjusting your search or filter.
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in Courses)
        {
            <div class="col">
                <CourseCard Course="course" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public required List<Course> Courses { get; set; }
}

