@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.FullName</strong>. Your enrollment request for
            <strong>@_selectedCourseTitle</strong> has been received.</p>
        <p>You will receive a confirmation at <strong>@_model.Email</strong>.</p>
        <hr />
        <a href="catalog" class="btn btn-outline-success">Back to Catalog</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name</label>
                    <InputText id="fullName" class="form-control" @bind-Value="_model.FullName" />
                    <ValidationMessage For="() => _model.FullName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId"
                               placeholder="e.g., CS012345" />
                    <ValidationMessage For="() => _model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="email" class="form-label">Email Address</label>
                    <InputText id="email" class="form-control" @bind-Value="_model.Email" />
                    <ValidationMessage For="() => _model.Email" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in _courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.CourseId" />
                </div>

                <div class="mb-3">
                    <label for="comments" class="form-label">Comments (optional)</label>
                    <InputTextArea id="comments" class="form-control" rows="3" @bind-Value="_model.Comments" />
                    <ValidationMessage For="() => _model.Comments" />
                </div>

                <button type="submit" class="btn btn-primary" disabled="@_isSubmitting">
                    @(_isSubmitting ? "Submitting…" : "Submit Enrollment Request")
                </button>
            </EditForm>
        </div>

        <div class="col-lg-4">
            <div class="card bg-light">
                <div class="card-body">
                    <h5 class="card-title">ℹ️ How It Works</h5>
                    <ol class="mb-0">
                        <li>Fill out your details and select a course.</li>
                        <li>Submit the form to request enrollment.</li>
                        <li>You'll receive a confirmation email with next steps.</li>
                    </ol>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private EnrollmentRequest _model = new();
    private List<Course> _courses = [];
    private bool _submitted;
    private bool _isSubmitting;
    private string _selectedCourseTitle = string.Empty;

    [SupplyParameterFromQuery(Name = "courseId")]
    private int? PreselectedCourseId { get; set; }

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();

        if (PreselectedCourseId.HasValue)
        {
            _model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        _isSubmitting = true;
        try
        {
            CatalogService.SubmitEnrollmentRequest(_model);
            var course = CatalogService.GetCourse(_model.CourseId);
            _selectedCourseTitle = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
            _submitted = true;
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}

